sql:
SELECT COUNT(relationship_id) 
FROM family_relationships 
WHERE relationship_type = 'spouse';

SELECT class_name
FROM passenger_classes
WHERE class_id = 0;

SELECT COUNT(DISTINCT T2.passenger_id) AS survivor_count
FROM family_relationships AS T2
WHERE T2.relationship_type = 'spouse' AND EXISTS (
    SELECT 1 FROM survival_reasons AS T1
    WHERE T1.survival_reason = 'Rescued by lifeboat' AND T1.survival_id = T2.relationship_id
);

external_knowledge:
- '1st Class' refers to the highest class of travel on the ship;
- 'survival_reason' includes various reasons why passengers survived the voyage;
- 'embarkation_points' are the locations where passengers boarded the ship.

sql:
SELECT MAX(relationship_count) AS max_connections
FROM (
  SELECT COUNT(relationship_id) AS relationship_count
  FROM family_relationships
  GROUP BY relationship_type
) AS relationship_counts;

SELECT COUNT(*) 
FROM survival_reasons 
WHERE survival_reason = 'Swam to safety';

external_knowledge:
- "blooms of family names" refers to the names of families;
- "age group names" are the categories that classify the age of family members;
- "tendrils of relationships" metaphorically represent the individual relationships within a family;
- "intertwining their roots" implies the connections or relationships that exist within a family.

sql:
SELECT survival_reason, COUNT(survival_id) AS total_survival_reasons
FROM survival_reasons
GROUP BY survival_reason;
